  ('disabled-0a2fc18c-moex-00044', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '假設A產品為劣等財且其市場的供需法則都成立。在其他條件不變下，下 列何者會使A產品的均衡價格及均衡數量都增加？', '["消費者的所得增加", "消費者的所得減少", "政府對生產A產品的廠商課徵從量稅", "政府對生產A產品的廠商進行補貼"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00045', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '假設生產 15 單位的產品 A 的平均成本為 60 元，當產品 A 的產量增加至 16單位時，平均成本增加為65元，則第16單位的產品A邊際成本為何？', '["60元", "70元", "110元", "140元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00046', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '假設廠商A所面臨的需求曲線為一水平線，下列敘述何者正確？', '["廠商可以進行第一級完全差別取價", "廠商可以進行兩階段訂價法（two-parttariffpricing）", "廠商的邊際收入曲線為負斜率、位於需求曲線下方", "廠商完全沒有影響價格的能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00047', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '根據某地方新聞報導：「本區雖然只有少數幾家海鮮漁獲供應商，競爭其 實很激烈的。各家海鮮的品質都很不錯，種類也都差不多，但業者為了搶 生意，往往不惜削價競爭，到最後消費者還是最大的贏家。」下列何者最 能刻劃這個市場的競爭模式？', '["完全競爭", "古爾諾（Cournot）競爭", "伯傳特（Bertrand）競爭", "獨占性競爭"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00048', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '假設 R 國與 U 國正在進行戰爭，兩國分別可以採用的策略為：繼續戰爭 （續戰）及和解。下表為兩國的賽局報酬矩陣（payoffmatrix），括號內數 值依序為R國的報酬、U國的報酬，則Nash均衡為何？ U國 續戰 和解 續戰 (-10,-10) (-15,-5) R國 和解 (-14,-12) (-12,-6)', '["R國採取和解，U國採取續戰", "R國採取續戰，U國採取和解", "兩國都採取和解", "Nash均衡不存在"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00049', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '假設某利潤極大廠商面對完全競爭的產品市場與勞動市場，產品價格為P， 工資為 W，其生產函數為 Y=L0.5 K0.5，其中 Y 為產量，勞動量 L=1，倘 若原本資本量K=4，後來增加變為16，則實質工資（W/P）與勞動所得占 產出價值的比率（WL/PY）分別會如何變動？', '["W/P變為原來的2倍，WL/PY不變", "W/P變為原來的1/2，WL/PY變為原來的2倍", "W/P變為原來的4倍，WL/PY不變", "W/P變為原來的1/4，WL/PY變為原來的4倍"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00050', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '考慮一個原先處於均衡狀態的撰寫電腦程式的勞動市場，且市場中的供需 法則均成立。在其他條件不變下，下列兩個事件同時發生對此一勞動市場 均衡工資及均衡勞動僱用量的影響為何？', '["許多大學增設資訊工程學系", "人工智慧的發展取代了程式設計師的工作", "均衡工資增加，且均衡勞動僱用量減少", "均衡工資減少，但均衡勞動僱用量的變化則不確定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00051', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '在中古車市場中出現買主不了解中古車的真實價值，因此降低最高的願付 價格來保障自己可能蒙受的損失，卻反而造成買到的都是品質差的車輛， 此現象稱為下列何者？', '["逆向選擇", "正向選擇", "道德風險", "風險愛好"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00052', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '假設社會只有甲、乙兩人，對於某公共財的需求曲線分別為 Q=26-P 及 Q=15-0.5P，其中P及Q分別為價格及數量，供給曲線為Q=P。下列敘 述何者錯誤？', '["社會最適訂價為11", "社會最適數量為14", "如能差別取價，甲需支付的價格為12", "如能差別取價，乙需支付的價格為2"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL),
  ('disabled-0a2fc18c-moex-00053', 'disabled-0a2fc18c', 'disabled-0a2fc18c-moex-114-d3ff7f6b', 'sub-disabled-0a2fc18c-04', NULL, 'single_choice', '假設A國沒有技術進步，且每人平均資本存量高於黃金法則（goldenrule） 下的每人平均資本存量。現若該國儲蓄率上升，根據梭羅模型（Solow model），該國長期：', '["每人平均產出及每人平均消費皆上升", "每人平均產出及每人平均消費皆下降", "每人平均產出上升但每人平均消費下降", "每人平均產出下降但每人平均消費上升"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:24+00:00", "source_pdf_sha1": "b81cfb4da5a0", "answer_pdf_sha1": "a2fead896f0a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "306", "s": "0804", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "經建行政"}'::jsonb, NULL)
